#include <iostream>
#include <stack>
#include <vector>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) {
        cin >> nums[i];
    }
    vector<int> result(n, -1);
    stack<int> st;
    for (int i = 0; i < n * 2; i++) {
        while (!st.empty() && nums[st.top()] < nums[i % n]) {
            result[st.top()] = nums[i % n];
            st.pop();
        }
        st.push(i % n);
    }
    for (int i = 0; i < n; i++) {
        cout << result[i] << " ";
    }
    return 0;
}

